## 解决方案（推荐改 evaluator）：正确从 initial 里取“参数 dict”
把 `_load_initial_vars_by_id()` 改成：优先取 `turn["parameters"]`（最后一轮），而不是把整个 `initial_parameters` list 当 variables 返回。

直接给你一个可用的最小 patch：

```python
def _extract_vars_from_episode_obj(ep: Dict[str, Any]) -> Dict[str, Any]:
    """
    兼容 episode 里：
    - ep["variables"] 是 dict（老格式）
    - ep["initial_parameters"] 是 list[turn]，turn["parameters"] 是 dict（新格式）
    - ep["initial_parameters"] 是 dict（极少数兼容）
    """
    if not isinstance(ep, dict):
        return {}
    v = ep.get("variables")
    if isinstance(v, dict):
        return v

    ip = ep.get("initial_parameters")
    # 新格式：list[turn]
    if isinstance(ip, list):
        for it in reversed(ip):
            if isinstance(it, dict) and isinstance(it.get("parameters"), dict):
                return it["parameters"]
        return {}
    # 旧兼容：dict
    if isinstance(ip, dict):
        return ip
    return {}

def _load_initial_vars_by_id(initial_path: str, sample_id: str) -> Dict[str, Any]:
    with open(initial_path, "r", encoding="utf-8") as f:
        txt = f.read().strip()
    try:
        obj = json.loads(txt)
        if isinstance(obj, list):
            for it in obj:
                if isinstance(it, dict) and str(it.get("id")) == str(sample_id):
                    return _extract_vars_from_episode_obj(it)
        if isinstance(obj, dict):
            if sample_id in obj and isinstance(obj[sample_id], dict):
                return _extract_vars_from_episode_obj(obj[sample_id])
            if isinstance(obj.get("data"), list):
                for it in obj["data"]:
                    if isinstance(it, dict) and str(it.get("id")) == str(sample_id):
                        return _extract_vars_from_episode_obj(it)
    except Exception:
        pass

    # jsonl fallback
    with open(initial_path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                it = json.loads(line)
            except Exception:
                continue
            if isinstance(it, dict) and str(it.get("id")) == str(sample_id):
                return _extract_vars_from_episode_obj(it)
    return {}
```

改完后，`base_vars` 就会是你想要的 `{WBOOTM0: 3.451, ...}` 这种 dict，`_merge_and_clip_vars` 就不会再 `dict(list)` 崩。

